import{_ as l,c as a,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Changelog: Version History and Updates | OpenSkills","description":"View OpenSkills version history and release notes. Track new features like update command, symlink support, private repo access, and bug fixes across all releases.","frontmatter":{"title":"Changelog: Version History and Updates | OpenSkills","sidebarTitle":"Changelog","subtitle":"Changelog: Version History and Updates","description":"View OpenSkills version history and release notes. Track new features like update command, symlink support, private repo access, and bug fixes across all releases.","tags":["changelog","version history"],"order":1},"headers":[],"relativePath":"numman-ali/openskills/changelog/changelog/index.md","filePath":"numman-ali/openskills/changelog/changelog/index.md"}'),s={name:"numman-ali/openskills/changelog/changelog/index.md"};function o(r,e,n,d,c,u){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>This page records OpenSkills version history, helping you understand new features, improvements, and bug fixes in each version.</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - Refresh installed skills from recorded sources (default: refresh all)</li><li><strong>Source metadata tracking</strong> - Installation now records source information for reliable skill updates</li></ul><h3 id="improvements" tabindex="-1">Improvements <a class="header-anchor" href="#improvements" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ul><li><strong>Multi-skill reading</strong> - The <code>openskills read</code> command now supports comma-separated skill name lists</li><li><strong>Usage instructions</strong> - Improved shell environment prompt messages for the read command</li><li><strong>README</strong> - Added update guide and manual usage instructions</li></ul><h3 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><strong>Update experience optimization</strong> - Skip skills without source metadata and list these skills to prompt reinstallation</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="improvements-1" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-1" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ul><li><strong>README</strong> - Clarified project-local default installation method, removed redundant sync prompts</li><li><strong>Installation messages</strong> - Installer now clearly distinguishes between project-local default installation and the <code>--global</code> option</li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="improvements-2" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-2" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ul><li><strong>Documentation and AGENTS.md guidance</strong> - All command examples and generated usage instructions now consistently use <code>npx openskills</code></li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="bug-fixes-1" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes-1" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><strong>Windows installation</strong> - Fixed path validation issues on Windows systems (&quot;Security error: Installation path outside target directory&quot;)</li><li><strong>CLI version</strong> - <code>npx openskills --version</code> now correctly reads the version number from package.json</li><li><strong>Root directory SKILL.md</strong> - Fixed installation issues for single-skill repositories where SKILL.md is in the repository root</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="new-features-1" tabindex="-1">New Features <a class="header-anchor" href="#new-features-1" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><p><strong>Symlink support</strong> - Skills can now be installed via symlinks to the skills directory (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>Supports git-based skill updates through symlinks created from cloned repositories</li><li>Supports local skill development workflows</li><li>Broken symlinks are gracefully skipped</li></ul></li><li><p><strong>Configurable output path</strong> - sync command now supports <code>--output</code> / <code>-o</code> option (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>Can sync to any <code>.md</code> file (e.g., <code>.ruler/AGENTS.md</code>)</li><li>Automatically creates file and adds title if file doesn&#39;t exist</li><li>Automatically creates nested directories if needed</li></ul></li><li><p><strong>Local path installation</strong> - Supports installing skills from local directories (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>Supports absolute paths (<code>/path/to/skill</code>)</li><li>Supports relative paths (<code>./skill</code>, <code>../skill</code>)</li><li>Supports tilde expansion (<code>~/my-skills/skill</code>)</li></ul></li><li><p><strong>Private git repository support</strong> - Supports installing skills from private repositories (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>SSH URLs (<code>git@github.com:org/private-skills.git</code>)</li><li>HTTPS URLs with authentication</li><li>Automatically uses system SSH keys</li></ul></li><li><p><strong>Comprehensive test suite</strong> - 88 tests across 6 test files</p><ul><li>Unit tests for symlink detection, YAML parsing</li><li>Integration tests for install, sync commands</li><li>End-to-end tests for complete CLI workflows</li></ul></li></ul><h3 id="improvements-3" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-3" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ul><li><p><strong><code>--yes</code> flag now skips all prompts</strong> - Fully non-interactive mode, suitable for CI/CD (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>No prompt when overwriting existing skills</li><li>Displays <code>Overwriting: &lt;skill-name&gt;</code> message when skipping prompts</li><li>All commands can now run in headless environments</li></ul></li><li><p><strong>CI workflow reordering</strong> - Build steps now run before tests</p><ul><li>Ensures <code>dist/cli.js</code> exists for end-to-end testing</li></ul></li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li><strong>Path traversal protection</strong> - Validates that installation paths stay within target directory</li><li><strong>Symlink dereferencing</strong> - <code>cpSync</code> uses <code>dereference: true</code> to safely copy symlink targets</li><li><strong>Non-greedy YAML regex</strong> - Prevents potential ReDoS attacks in frontmatter parsing</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="bug-fixes-2" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes-2" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li>README documentation cleanup - Removed duplicate sections and incorrect flags</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="new-features-2" tabindex="-1">New Features <a class="header-anchor" href="#new-features-2" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><code>--universal</code> flag, installs skills to <code>.agent/skills/</code> instead of <code>.claude/skills/</code><ul><li>Suitable for multi-agent environments (Claude Code + Cursor/Windsurf/Aider)</li><li>Avoids conflicts with Claude Code native marketplace plugins</li></ul></li></ul><h3 id="improvements-4" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-4" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ul><li>Project-local installation is now the default option (previously global installation)</li><li>Skills install to <code>./.claude/skills/</code> by default</li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="new-features-3" tabindex="-1">New Features <a class="header-anchor" href="#new-features-3" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li>Comprehensive single-page README with technical deep dive</li><li>Side-by-side comparison with Claude Code</li></ul><h3 id="bug-fixes-3" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes-3" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li>Location badges now correctly display <code>project</code> or <code>global</code> based on installation location</li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="new-features-4" tabindex="-1">New Features <a class="header-anchor" href="#new-features-4" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li>Initial release</li><li><code>npx openskills install &lt;source&gt;</code> - Install skills from GitHub repositories</li><li><code>npx openskills sync</code> - Generate <code>&lt;available_skills&gt;</code> XML for AGENTS.md</li><li><code>npx openskills list</code> - Display installed skills</li><li><code>npx openskills read &lt;name&gt;</code> - Load skill content for agents</li><li><code>npx openskills manage</code> - Interactive skill deletion</li><li><code>npx openskills remove &lt;name&gt;</code> - Remove specific skills</li><li>Interactive TUI interface for all commands</li><li>Supports Anthropic&#39;s SKILL.md format</li><li>Progressive disclosure (load skills on-demand)</li><li>Bundled resources support (references/, scripts/, assets/)</li></ul><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th></tr></thead><tbody><tr><td>Changelog original</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const m=l(s,[["render",o]]);export{p as __pageData,m as default};
